import 'package:flutter_test/flutter_test.dart'; import 'package:googlepro/features/auth/model/auth_user.dart'; void main() { group('AuthUser', () { test('initials from full name', () { const u = AuthUser(uid: 'u1', email: 'a@b.com', displayName: 'John Doe'); expect(u.initials, 'JD'); }); test('initials from email if no name', () { const u = AuthUser(uid: 'u1', email: 'alice@b.com'); expect(u.initials, 'A'); }); test('toJson/fromJson round trip', () { const u = AuthUser(uid: 'u1', email: 'a@b.com', displayName: 'Test'); final j = u.toJson(); final r = AuthUser.fromJson(j); expect(r.uid, u.uid); expect(r.email, u.email); expect(r.displayName, u.displayName); }); test('firstName is first word of displayName', () { const u = AuthUser(uid: 'u1', email: 'a@b.com', displayName: 'John Doe'); expect(u.firstName, 'John'); }); }); }